// Sample roadmap items with dependency declarations.
// Each item can declare: blocks (items it blocks) and depends_on (items it requires first)
const items = [
  { id: 'I001', title: 'Data model v2 refactor', team: 'backend', estimated_weeks: 6, status: 'in-progress', depends_on: [], blocks: ['I002', 'I003', 'I005'] },
  { id: 'I002', title: 'API v2 endpoints', team: 'backend', estimated_weeks: 4, status: 'planned', depends_on: ['I001'], blocks: ['I004', 'I006'] },
  { id: 'I003', title: 'Real-time sync engine', team: 'backend', estimated_weeks: 5, status: 'planned', depends_on: ['I001'], blocks: ['I007'] },
  { id: 'I004', title: 'Mobile app (iOS)', team: 'mobile', estimated_weeks: 8, status: 'planned', depends_on: ['I002'], blocks: ['I008'] },
  { id: 'I005', title: 'Reporting data pipeline', team: 'data', estimated_weeks: 3, status: 'planned', depends_on: ['I001'], blocks: ['I009'] },
  { id: 'I006', title: 'SSO integration', team: 'backend', estimated_weeks: 3, status: 'planned', depends_on: ['I002'], blocks: [] },
  { id: 'I007', title: 'Offline mode support', team: 'mobile', estimated_weeks: 4, status: 'planned', depends_on: ['I003'], blocks: [] },
  { id: 'I008', title: 'Mobile app (Android)', team: 'mobile', estimated_weeks: 6, status: 'planned', depends_on: ['I004'], blocks: [] },
  { id: 'I009', title: 'Executive dashboard', team: 'frontend', estimated_weeks: 4, status: 'planned', depends_on: ['I005'], blocks: [] },
  { id: 'I010', title: 'Self-serve onboarding flow', team: 'frontend', estimated_weeks: 3, status: 'planned', depends_on: [], blocks: [] }
];
return [{ json: { items, total: items.length } }];

const { items } = $input.first().json;
// Build adjacency map
const itemMap = {};
for (const item of items) itemMap[item.id] = item;

// Detect circular dependencies using DFS
const detectCycles = () => {
  const visited = {}, stack = {}, cycles = [];
  const dfs = (id, path) => {
    if (stack[id]) { cycles.push([...path, id]); return; }
    if (visited[id]) return;
    visited[id] = true; stack[id] = true;
    for (const dep of (itemMap[id]?.depends_on || [])) dfs(dep, [...path, id]);
    stack[id] = false;
  };
  for (const id of Object.keys(itemMap)) dfs(id, []);
  return cycles;
};

// Find items with no dependencies (roots)
const roots = items.filter(i => i.depends_on.length === 0).map(i => i.id);

// Compute longest path (critical path) from each root using topological sort
const computeLongestPath = () => {
  const dist = {};
  for (const item of items) dist[item.id] = item.estimated_weeks || 0;
  // Simple relaxation — iterate N times
  for (let pass = 0; pass < items.length; pass++) {
    for (const item of items) {
      for (const dep of (item.depends_on || [])) {
        if (itemMap[dep]) {
          dist[item.id] = Math.max(dist[item.id], dist[dep] + (item.estimated_weeks || 0));
        }
      }
    }
  }
  return dist;
};

const cycles = detectCycles();
const longestPath = computeLongestPath();
const criticalPath = Object.entries(longestPath).sort((a,b) => b[1]-a[1]).slice(0,5).map(([id, weeks]) => ({ id, title: itemMap[id]?.title, cumulative_weeks: weeks }));
const blockers = items.filter(i => i.blocks && i.blocks.length > 0).sort((a,b) => b.blocks.length - a.blocks.length).map(i => ({ id: i.id, title: i.title, blocks_count: i.blocks.length, blocks: i.blocks }));

return [{ json: {
  items,
  cycles: cycles.length > 0 ? cycles : null,
  has_cycles: cycles.length > 0,
  critical_path: criticalPath,
  blockers,
  roots,
  total: items.length
} }];

const { cycles, has_cycles, critical_path, blockers, roots, total } = $input.first().json;
const cycleLines = has_cycles ? cycles.map(c => `  CYCLE: ${c.join(' → ')}`).join('\n') : '  None detected';
const criticalLines = (critical_path || []).map(c => `  ${c.id}: ${c.title} (${c.cumulative_weeks} weeks cumulative)`).join('\n');
const blockerLines = (blockers || []).slice(0, 5).map(b => `  ${b.id}: ${b.title} — blocks ${b.blocks_count} item(s): ${b.blocks.join(', ')}`).join('\n');
const report = [
  `ROADMAP DEPENDENCY MAP`,
  `Items analysed: ${total} | Roots (no dependencies): ${roots.join(', ')}`,
  ``,
  `CIRCULAR DEPENDENCY CHECK:`,
  cycleLines,
  ``,
  `CRITICAL PATH (longest cumulative duration):`,
  criticalLines,
  ``,
  `TOP BLOCKERS (items blocking the most downstream work):`,
  blockerLines,
].join('\n');
return [{ json: { ...($input.first().json), report_text: report } }];
